import { useState } from "react";
import axios from "axios";

function App() {
  const [form, setForm] = useState({
    name: "",
    tagline: "",
    description: "",
    services: "",
    contact: ""
  });

  const [html, setHtml] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const generateWebsite = async () => {
    try {
      const res = await axios.post("http://127.0.0.1:8000/generate", {
        ...form,
        services: form.services.split(",") // convert to list
      });

      setHtml(res.data.html);
    } catch (err) {
      console.error(err);
      alert("Something went wrong");
    }
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>🚀 Website Generator</h1>

      <input name="name" placeholder="Business Name" onChange={handleChange} /><br /><br />
      <input name="tagline" placeholder="Tagline" onChange={handleChange} /><br /><br />
      <input name="description" placeholder="Description" onChange={handleChange} /><br /><br />
      <input name="services" placeholder="Services (comma separated)" onChange={handleChange} /><br /><br />
      <input name="contact" placeholder="Contact" onChange={handleChange} /><br /><br />

      <button onClick={generateWebsite}>Generate Website</button>

      <h2>Preview</h2>

      <iframe
        srcDoc={html}
        title="preview"
        width="100%"
        height="500px"
        style={{ border: "1px solid black", marginTop: "20px" }}
      />
    </div>
  );
}

export default App;
